#include <bits/stdc++.h>
using namespace std;

const int N = 5e5 + 10;
int tag[4 * N], tag0[4 * N], tag1[4 * N];
int a[N];

struct Info
{
    int l1, l0, r1, r0, m1, m0, c1, c0, len;
    void swap()
    {
        std::swap(l1, l0);
        std::swap(r1, r0);
        std::swap(m1, m0);
        std::swap(c1, c0);
    }
    void set1()
    {
        l1 = r1 = m1 = c1 = len;
        l0 = r0 = m0 = c0 = 0;
    }
    void set0()
    {
        l1 = r1 = m1 = c1 = 0;
        l0 = r0 = m0 = c0 = len;
    }
    Info() : l1(0), l0(0), r1(0), r0(0), m1(0), m0(0), c1(0), c0(0), len(0) {}
    Info(int p, int q, int length) : len(length) {
        l1 = r1 = m1 = c1 = p;
        l0 = r0 = m0 = c0 = q;
    }
    Info operator+ (const Info &o) const
    {
        Info res;
        res.len = len + o.len;
        res.l1 = (l1 == len) ? l1 + o.l1 : l1;
        res.l0 = (l0 == len) ? l0 + o.l0 : l0;
        res.r1 = (o.r1 == o.len) ? r1 + o.r1 : o.r1;
        res.r0 = (o.r0 == o.len) ? r0 + o.r0 : o.r0;
        res.m1 = max({m1, o.m1, r1 + o.l1});
        res.m0 = max({m0, o.m0, r0 + o.l0});
        res.c1 = c1 + o.c1;
        res.c0 = c0 + o.c0;
        return res;
    }
}d[4 * N];

inline void push_up(int x) {
    d[x] = d[x * 2] + d[x * 2 + 1];
}

void push_down(int x, int ln, int rn) {
    int l = x * 2, r = x * 2 + 1;
    if(tag1[x])
    {
        d[l].set1();
        tag1[l] = 1;
        tag0[l] = 0;
        tag[l] = 0;
        d[r].set1();
        tag1[r] = 1;
        tag0[r] = 0;
        tag[r] = 0;
        tag1[x] = 0;
    }
    if(tag0[x])
    {
        d[l].set0();
        tag0[l] = 1;
        tag1[l] = 0;
        tag[l] = 0;
        d[r].set0();
        tag0[r] = 1;
        tag1[r] = 0;
        tag[r] = 0;
        tag0[x] = 0;
    }
    if (tag[x]) {
        d[l].swap();
        d[r].swap();
        tag[l] ^= 1;
        tag[r] ^= 1;
        tag[x] = 0;
    }
}

void build(int x, int l, int r) {
    if (l == r) {
        int p = a[l];
        int q = 1 - p;
        d[x] = Info(p, q, 1);
        return;
    }
    int mid = (l + r) >> 1;
    build(x * 2, l, mid);
    build(x * 2 + 1, mid + 1, r);
    push_up(x);
}

void update(int x, int l, int r, int a, int b) {
    if (a <= l && r <= b) {
        d[x].swap();
        tag[x] ^= 1;
        return;
    }
    int mid = (l + r) >> 1;
    push_down(x, mid - l + 1, r - mid);
    if (a <= mid) 
        update(x * 2, l, mid, a, b);
    if (b > mid) 
        update(x * 2 + 1, mid + 1, r, a, b);
    push_up(x);
}

void update1(int x, int l, int r, int a, int b) {
    if (a <= l && r <= b) {
        d[x].set1();
        tag1[x] = 1;
        tag0[x] = 0;
        tag[x] = 0;
        return;
    }
    int mid = (l + r) >> 1;
    push_down(x, mid - l + 1, r - mid);
    if (a <= mid) 
        update1(x * 2, l, mid, a, b);
    if (b > mid) 
        update1(x * 2 + 1, mid + 1, r, a, b);
    push_up(x);
}

void update0(int x, int l, int r, int a, int b) {
    if (a <= l && r <= b) {
        d[x].set0();
        tag0[x] = 1;
        tag1[x] = 0;
        tag[x] = 0;
        return;
    }
    int mid = (l + r) >> 1;
    push_down(x, mid - l + 1, r - mid);
    if (a <= mid) 
        update0(x * 2, l, mid, a, b);
    if (b > mid) 
        update0(x * 2 + 1, mid + 1, r, a, b);
    push_up(x);
}

Info query(int x, int l, int r, int a, int b) {
    if (a <= l && r <= b) 
        return d[x];
    int mid = (l + r) >> 1;
    push_down(x, mid - l + 1, r - mid);
    if (b <= mid) return query(x * 2, l, mid, a, b);
    if (a > mid) return query(x * 2 + 1, mid + 1, r, a, b);
    return query(x * 2, l, mid, a, b) + query(x * 2 + 1, mid + 1, r, a, b);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0);
    int n, q;
    cin >> n >> q;
    for (int i = 1; i <= n; i++) 
        cin >> a[i];
    build(1, 1, n);
    while (q--) {
        int op, x, y;
        cin >> op >> x >> y;
        x++; y++;
        if (op == 0) 
            update0(1, 1, n, x, y);
        else if(op == 1)
            update1(1, 1, n, x, y);
        else if(op == 2)
            update(1, 1, n, x, y);
        else if(op == 3)
            cout << query(1, 1, n, x, y).c1 << '\n';
        else
            cout << query(1, 1, n, x, y).m1 << '\n';
    }
    return 0;
}
